class Solution {
public:
    bool canPartitionKSubsets(vector<int>& nums, int k) {
        int sum = 0;
        for (int num : nums) sum += num;
        if (sum % k != 0) return false;
        int target = sum / k;
        sort(nums.rbegin(), nums.rend());
        vector<int> groups(k, 0);
        return dfs(nums, groups, target, 0);
    }

    bool dfs(vector<int>& nums, vector<int>& groups, int target, int index) {
        if (index == nums.size()) {
            for (int group : groups) if (group != target) return false;
            return true;
        }
        for (int i = 0; i < groups.size(); ++i) {
            if (groups[i] + nums[index] <= target) {
                groups[i] += nums[index];
                if (dfs(nums, groups, target, index + 1)) return true;
                groups[i] -= nums[index];
            }
        }
        return false;
    }
};
